SELECT source, AVG(emv_value) AS average_emv
FROM emv_tracker
GROUP BY source;

SELECT emv_index
FROM infectious_disease
WHERE date = '2000-01-07';

SELECT AVG(emv_index) AS average_emv_index
FROM infectious_disease
WHERE country = 'China';

SELECT emv_value
FROM emv_tracker
WHERE tracker_id = 1;

SELECT uncertainty_value, date
FROM trade_policy
WHERE impact_level = 'medium';

SELECT MAX(uncertainty_value) AS max_uncertainty_value
FROM trade_policy
WHERE country = 'Japan';

SELECT country, AVG(uncertainty_value) AS average_uncertainty
FROM trade_policy
GROUP BY country;

SELECT date
FROM trade_policy
WHERE uncertainty_value = (SELECT MAX(uncertainty_value) FROM trade_policy);
